es = Elasticsearch(['http://localhost:9200'])

def index_document(index_name, document):
    try:
        response = es.index(index=index_name, body=document)
        logger.info(f"Document indexed successfully. Response: {response}")
    except Exception as e:
        logger.error(f"Failed to index document: {e}")

def search_documents(index_name, query):
    try:
        response = es.search(index=index_name, body={"query": {"match": query}})
        logger.info(f"Search results: {response['hits']['hits']}")
        return response['hits']['hits']
    except Exception as e:
        logger.error(f"Failed to search documents: {e}")
        return []

def aggregate_logs(index_name, aggregation_body):
    try:
        response = es.search(index=index_name, body=aggregation_body)
        logger.info(f"Aggregation results: {response['aggregations']}")
        return response['aggregations']
    except Exception as e:
        logger.error(f"Failed to perform aggregation: {e}")
        return {}

